# ---------------------------------------------------------------------------
# GHANA NATIONAL COLOUR PALETTE  —  Midnight & Gold Edition
# ---------------------------------------------------------------------------

class GhanaColors:
    """Hex codes for Ghana's national identity palette."""

    # Flag primaries
    RED:   str = "#CF0921"
    GOLD:  str = "#FCD116"
    GREEN: str = "#006B3F"
    BLACK: str = "#000000"

    # Priority tier aliases
    CRITICAL: str = RED
    HIGH:     str = GOLD
    STABLE:   str = GREEN
    ACCENT:   str = BLACK

    # Extended UI palette
    LIGHT_GOLD:   str = "#FFF3CD"
    DARK_GREEN:   str = "#004D2C"
    LIGHT_RED:    str = "#FDECEA"
    NEUTRAL_GREY: str = "#F5F5F5"

    # Midnight & Gold dark-theme palette
    OBSIDIAN:         str = "#0E1117"
    OBSIDIAN_SURFACE: str = "#161B22"
    OBSIDIAN_BORDER:  str = "#30363D"
    GLASS_BG:         str = "rgba(22,27,34,0.72)"
    GLASS_BORDER:     str = "rgba(252,209,22,0.18)"
    GOLD_GLOW:        str = "rgba(252,209,22,0.12)"
    TEXT_PRIMARY:     str = "#E6EDF3"
    TEXT_MUTED:       str = "#8B949E"
    GOLD_BRIGHT:      str = "#FFD700"

    @classmethod
    def for_score(cls, score: float) -> str:
        """Return the appropriate hex color for a given priority score."""
        if score > THRESHOLD_CRITICAL:
            return cls.CRITICAL
        if score > THRESHOLD_HIGH:
            return cls.HIGH
        return cls.STABLE

